CREATE TABLE public.generated_casos (id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, slug text NOT NULL UNIQUE, category text NOT NULL, name text NOT NULL, location text NOT NULL, debt_amount text NOT NULL, solution text NOT NULL, headline text NOT NULL, dek text NOT NULL, read_time text, hero_alt text, sections jsonb NOT NULL DEFAULT '[]'::jsonb, faq jsonb NOT NULL DEFAULT '[]'::jsonb, keywords text[] NOT NULL DEFAULT '{}', seo_title text, meta_description text, status text NOT NULL DEFAULT 'published', published_at timestamp with time zone DEFAULT now(), created_at timestamp with time zone NOT NULL DEFAULT now(), updated_at timestamp with time zone NOT NULL DEFAULT now()); GRANT SELECT ON public.generated_casos TO anon; GRANT SELECT ON public.generated_casos TO authenticated; GRANT ALL ON public.generated_casos TO service_role; ALTER TABLE public.generated_casos ENABLE ROW LEVEL SECURITY; CREATE POLICY "Public can read published casos" ON public.generated_casos FOR SELECT USING (status = 'published'); CREATE POLICY "Admins manage casos" ON public.generated_casos FOR ALL TO authenticated USING (public.has_role(auth.uid(), 'admin')) WITH CHECK (public.has_role(auth.uid(), 'admin')); CREATE TRIGGER update_generated_casos_updated_at BEFORE UPDATE ON public.generated_casos FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column(); CREATE INDEX idx_generated_casos_status_pub ON public.generated_casos (status, published_at DESC);